import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const repoRoot = path.resolve(__dirname, '..');
const electronDir = path.join(repoRoot, 'electron');
const entryPath = path.join(electronDir, 'preload.cjs');
const outputPath = path.join(electronDir, 'preload.bundle.cjs');
const LOCAL_REQUIRE_PATTERN = /require\((['"])(\.\/[^'"]+)\1\)/g;

function toModuleId(filePath) {
  return `./${path.posix.normalize(path.relative(electronDir, filePath).split(path.sep).join('/'))}`;
}

async function collectModules(filePath, modules = new Map()) {
  const resolvedPath = path.resolve(filePath);
  const moduleId = toModuleId(resolvedPath);
  if (modules.has(moduleId)) {
    return modules;
  }

  const code = await fs.readFile(resolvedPath, 'utf8');
  modules.set(moduleId, code);

  for (const match of code.matchAll(LOCAL_REQUIRE_PATTERN)) {
    await collectModules(path.resolve(path.dirname(resolvedPath), match[2]), modules);
  }

  return modules;
}

function indent(code) {
  return code
    .split('\n')
    .map((line) => `    ${line}`)
    .join('\n');
}

export async function buildPreloadBundle() {
  const modules = await collectModules(entryPath);
  const moduleEntries = [...modules.entries()]
    .map(([moduleId, code]) => `  ${JSON.stringify(moduleId)}: function(require, module, exports) {\n${indent(code)}\n  }`)
    .join(',\n');

  const bundle = `// Generated by scripts/build-preload-bundle.mjs. Do not edit directly.\n` +
`(function() {\n` +
`  const modules = {\n${moduleEntries}\n  };\n` +
`  const cache = Object.create(null);\n` +
`  function resolveLocal(parentId, request) {\n` +
`    const parentParts = parentId.split('/');\n` +
`    parentParts.pop();\n` +
`    const parts = [...parentParts, request].join('/').split('/');\n` +
`    const resolved = [];\n` +
`    for (const part of parts) {\n` +
`      if (!part || part === '.') continue;\n` +
`      if (part === '..') {\n` +
`        resolved.pop();\n` +
`        continue;\n` +
`      }\n` +
`      resolved.push(part);\n` +
`    }\n` +
`    return './' + resolved.join('/');\n` +
`  }\n` +
`  function loadModule(moduleId) {\n` +
`    if (cache[moduleId]) return cache[moduleId].exports;\n` +
`    const factory = modules[moduleId];\n` +
`    if (!factory) throw new Error('Bundled preload module not found: ' + moduleId);\n` +
`    const module = { exports: {} };\n` +
`    cache[moduleId] = module;\n` +
`    factory((request) => request.startsWith('./') ? loadModule(resolveLocal(moduleId, request)) : require(request), module, module.exports);\n` +
`    return module.exports;\n` +
`  }\n` +
`  loadModule(${JSON.stringify(toModuleId(entryPath))});\n` +
`})();\n`;

  await fs.writeFile(outputPath, bundle);
}

if (process.argv[1] && import.meta.url === pathToFileURL(path.resolve(process.argv[1])).href) {
  buildPreloadBundle().catch((error) => {
    console.error(`[vlaina] Failed to build preload bundle: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  });
}
